    const dist = new Array(n).fill(Infinity);
    dist[0] = 0;
    const pq = new PriorityQueue((a, b) => a[0] - b[0]);
    pq.enqueue([0, 0]); // [time, node]

    while (!pq.isEmpty()) {
        const [time, u] = pq.dequeue();
        if (u === n - 1) break;
        if (time > dist[u]) continue;

        // Try to stay at current node
        if (time < dist[u]) {
            pq.enqueue([time + 1, u]);
        }

        // Try to take each outgoing edge
        for (const { v, start, end } of adj[u]) {
            // Check if we can use this edge at current time
            if (start <= time && time <= end) {
                // We can take this edge, move to v at time + 1
                const newTime = time + 1;
                if (newTime < dist[v]) {
                    dist[v] = newTime;
                    pq.enqueue([newTime, v]);
                }
            }
        }
    }

    return dist[n - 1] === Infinity ? -1 : dist[n - 1];
}
